    import torch
    X = np.asarray(X_raw, np.float32)
    if X.ndim == 2:
        X = X[None]
    assert X.ndim == 3 and X.shape[1:] == (SEQ_LEN, len(FEATURE_MANIFEST)), \
        f"expected (N, {SEQ_LEN}, {len(FEATURE_MANIFEST)}) raw windows, got {X.shape}"
